INSERT INTO questions (subject, exam_type, question, option_a, option_b, option_c, option_d, option_e, correct_answer, explanation, year) VALUES 
('English Language', 'WAEC', 'While Mr. Ade is _________, his son is a novice.', 'enlightened', 'competent', 'clever', 'experienced', NULL, 'D', 'The adjective "novice" is used in addressing someone who is fresh and inexperienced in a job. The opposite is experienced, expert, proficient, knowledgeable or skilful.', 2021), 
('English Language', 'WAEC', 'It is better to use _________ rather than _________ to get witnesses to court.', 'effort', 'coercion', 'influence', 'pressure', NULL, 'B', 'The noun "persuasion" denotes the acting of persuading, convincing or influencing people''s opinion. The opposite appropriate for the context is "coercion".', 2021), 
('English Language', 'WAEC', 'The animosity between Fatou and Sheku is shocking, considering the _________ they once shared.', 'friendship', 'coercion', 'peace', 'understanding', NULL, 'A', 'The noun "animosity" means hatred, hostility, bitterness, acrimony, enmity. The appropriate antonym is "friendship".', 2021), 
('English Language', 'WAEC', 'The reckless driver was admonished to _________.', 'cautious', 'responsible', 'reliable', 'considerate', NULL, 'A', 'The word "reckless" means careless, carefree, intermediate to danger or the consequences, rash, heedless. The appropriate antonym is "cautious".', 2021), 
('English Language', 'WAEC', 'The old man rebuked the thug and his children _________ him for doing so.', 'supported', 'commended', 'embraced', 'thanked', NULL, 'B', 'Rebuked means criticized or told off. The appropriate antonym is "commended" — meaning praised.', 2021), 
('English Language', 'WAEC', 'All drivers were enjoined to obtain _________ and not _________ licences.', 'genuine', 'fraudulent', 'fake', 'artificial', NULL, 'A', 'The opposite of "genuine" with reference to licences is "fake", not substandard or artificial.', 2021), 
('English Language', 'WAEC', 'There was an agitation for the law on libel to be re-enacted.', 'cautious', 'responsible', 'rejected', 'cancelled', NULL, 'C', 'The word "repeal" means to annul, invalidate or cancel as in "to repeal a law". The opposite is re-enact or re-establish.', 2021), 
('English Language', 'WAEC', 'The champions were elated after the tournament while the opponents _________.', 'baffled', 'dejected', 'pitiful', 'frightened', NULL, 'B', 'The noun "elated" denotes being extremely happy and excited; delighted, pleased, jubilant. The opposite of "elated" means displeased or dissatisfied — dejected.', 2021), 
('English Language', 'WAEC', 'The two political parties live today in _________ after four years of hostility.', 'happiness', 'amity', 'agreement', 'freedom', NULL, 'B', 'The noun "hostility" means hatred, antagonism, opposition to a party, group or persons; antagonism, enmity, animosity. The appropriate antonymous word is amity.', 2021), 
('English Language', 'WAEC', 'That engineer was said to have used _________ rather than _________ materials in the construction of the collapsed building.', 'excellent', 'recommend', 'quality', 'exceptional', NULL, 'C', 'The context is about building or engineering, where "quality" is most suitable as the opposite of "inferior".', 2021), 
('English Language', 'WAEC', 'I could not read what he wrote because his handwriting was _________.', 'dismissed', 'eligible', 'untidy', 'illegible', NULL, 'D', 'The adjective "illegible" is apposite to qualify a handwriting that is not clear enough to be read, unreadable or undecipherable.', 2021), 
('English Language', 'WAEC', 'When all the items on the agenda had been discussed, the meeting was _________.', 'adjourned', 'dissolved', 'dismissed', 'postponed', NULL, 'C', 'Adjourned is the appropriate diction to refer to a meeting that has been deferred, suspended or shifted to hold another time. "Postpone" is not closer in meaning to "adjourn".', 2021), 
('English Language', 'WAEC', '_________ degrees to outstanding personalities.', 'idea', 'assurance', 'belief', 'honorary', NULL, 'D', '"Honorary" is used in describing the holder of a position or title that is confer on him as a special honor rather than by normal channels; such award is given as an honour, with no duties attached and without payment.', 2021), 
('English Language', 'WAEC', 'His thoughtlessness is simply beyond _________.', 'idea', 'assurance', 'belief', 'honorary', NULL, 'C', 'The sentence should read "His thoughtlessness is simply beyond belief". Meaning that it is difficult to think or believe that the person has so much disregard for other''s feelings and the consequences of his actions.', 2021), 
('English Language', 'WAEC', 'Many groups had _________ from the plains of Eastern Europe.', 'migrated', 'immigrated', 'emigrated', 'fled', NULL, 'A', '"Migrate" is the general verb to refer to moving or relocating to live in another place or to relocate. When you are being specific about a particular country, "immigrate" will be appropriate.', 2021), 
('English Language', 'WAEC', 'After Mr. Julius retired, he made his first son a sole _________ his business accounts.', 'signatory', 'signer', 'subscriber', 'participant', NULL, 'B', '"Signatory" is apposite for the given sentence. It means being one of the people that have the access or right to sign an account or document.', 2021), 
('English Language', 'WAEC', 'The verb _________ in the given context is an action planned to prevent or cause another action to fail.', 'thwart', 'disrupt', 'prevent', 'abort', NULL, 'A', 'The verb "thwart" in the given context is an action planned to prevent or cause another action to fail, to stop another plan from succeeding.', 2021), 
('English Language', 'WAEC', 'She gave her poem to her teacher to _________ for the school magazine.', 'edit', 'correct', 'review', 'revise', NULL, 'A', 'The sentence should read, "She gave her poem to her teacher to edit for the school magazine", where "edit" means to review and correct in a way that is acceptable.', 2021), 
('English Language', 'WAEC', 'In the phrase "fundamental human right" the adjective "fundamental" denotes the right that is _________.', 'important', 'basic', 'essential', 'fundamental', NULL, 'B', 'In the phrase "fundamental human right" the adjective "fundamental" denotes the right that is important or essential and basic to citizens'' existence, and as the foundation for all other rights.', 2021), 
('English Language', 'WAEC', 'The right word is _________, an act of sovereign power granting a general pardon for a past offense.', 'amnesty', 'pardon', 'forgiveness', 'clemency', NULL, 'A', 'The right word is "amnesty" — an act of sovereign power granting a general pardon for a past offense. It is also called state pardon.', 2021), 
('English Language', 'WAEC', 'The principal raised his eyebrows at the student''s explanation. This means that the principal was:', 'unhappy about the explanation', 'rejected the explanation', 'considered the explanation', 'surprised by the explanation', NULL, 'D', 'To raise or cause eyebrows means to check or surprise people. The way he appeared raised eyebrows, meaning he was surprised.', 2021), 
('English Language', 'WAEC', 'Mary made a clean breast of everything. This means that Mary:', 'won everyone over', 'told the whole truth', 'did everything efficiently', 'changed the way things were done', NULL, 'B', '"Make a clean breast of something" means to confess something bad that you have done in order not to feel guilty or bad.', 2021), 
('English Language', 'WAEC', 'Had it not rained, I would have visited you. This means that:', 'I visited you', 'it did not rain and so I visited you', 'it rained so I did not visit you', 'it rained so I visited you', NULL, 'C', 'The sentence "Had it not rained, I would have visited you" is a conditional subjunctive statement that expresses action that did not happen when it was due for occurrence, because the condition was not fulfilled.', 2021), 
('English Language', 'WAEC', 'I hadn''t finished talking to Halima, when she snapped my head off. This means that she:', 'rudely interrupted me', 'hissed at me', 'ordered me to stop talking', 'severely criticised me', NULL, 'A', '"Snap someone''s head off" means to answer someone in a rude or unreasonably angry way; to yell or talk very angrily/harshly to someone.', 2021), 
('English Language', 'WAEC', 'Franca''s behaviour towards Edward leaves much to be desired. This means that Franca''s behaviour was:', 'unsatisfactory', 'appreciated', 'commendable', 'unexpected', NULL, 'A', '"Leaves much to be desired" is used to means something is not good at all or it is not close to being good.', 2021), 
('English Language', 'WAEC', 'The teacher truly had his heart in the right place. This means that he was:', 'kind and considerate', 'sharp and modest', 'simple and modest', 'focused and direct', NULL, 'A', '"Have one''s heart in the right place" means to be very excited or nervous about something anticipated; happily, overwhelmed about something to the point that one is speechless.', 2021), 
('English Language', 'WAEC', 'Only teachers could afford a car. This means that:', 'teachers could afford a car and nothing else', 'teachers and others could afford a car', 'nobody else could afford a car', 'few teachers could afford a car', NULL, 'C', '"Only teachers could afford a car" means teachers and no one else could afford a car.', 2021), 
('English Language', 'WAEC', 'The night watchman was given the marching orders because of his negligence. This means that he was:', 'promoted', 'dismissed', 'counselled', 'suspended', NULL, 'B', '"Marching orders" means to be relieved and dismissed from duties; to be sacked.', 2021), 
('English Language', 'WAEC', 'My friend is as dull as ditchwater. This means that my friend is:', 'dark in complexion', 'extremely boring', 'not intelligent', 'not a troublemaker', NULL, 'B', '"As dull as ditchwater" means not social, communicative and engaging. Extremely boring or very uninteresting.', 2021), 
('English Language', 'WAEC', 'The director sees Tim as the joker in the pack. This means the director considers Tim to be:', 'unpredictable', 'humorous', 'nonchalant', 'unruly', NULL, 'A', '"The joker in the pack" is someone, a situation or factor likely to have an unpredictable effect on events.', 2021), 
('English Language', 'WAEC', 'The adjective "strategic" as used in the given sentence means:', 'tactical', 'premeditated', 'well-thought off', 'planned', NULL, 'A', 'The adjective "strategic" means "tactical", "premeditated", "well-thought off" or "calculated".', 2021), 
('English Language', 'WAEC', 'The appropriate synonym for "proscription" as used in the given sentence is:', 'banning', 'prohibition', 'outlawing', 'exclusion', NULL, 'A', 'The appropriate synonym for "proscription" as used in the given context is banning. Other synonyms are: banning, prohibition, outlawing and exclusion.', 2021), 
('English Language', 'WAEC', 'The adjective "frustrating" in the sentence "Farmers sometimes go through the frustrating experience of having to watch their produce rot" means:', 'annoying', 'vexing', 'infuriating', 'provoking', NULL, 'A', 'The adjective "frustrating" in the sentence means annoying, vexing, infuriating, provoking, exasperating and bothersome.', 2021), 
('English Language', 'WAEC', 'The appropriate synonyms for "stunned" in the sentence "The acrobatic displays left the spectators stunned" is:', 'amazed', 'surprised', 'astounded', 'dazed', NULL, 'A', '"Stunned" is "astonished". Other similar words are: amazed, surprised, astounded, dazed and impressed.', 2021), 
('English Language', 'WAEC', 'The adjective "resplendent" in "Binetou looked quite resplendent in that red dress" means:', 'attractive', 'impressive', 'sive', 'colorful', NULL, 'A', '"Resplendent" means attractive, impressive, sive, colorful, shiny, stunning, dazzling, splendid, glittering, magnificent.', 2021), 
('English Language', 'WAEC', 'The adjective "mundane" could denote different things. However, as used in the sentence "It is foolish to depend entirely on mundane things" means:', 'physical', 'worldly', 'earthly', 'material', NULL, 'B', 'Context is very important in interpreting the meaning of a word. The adjective "mundane" as used in this sentence means material things as opposed to spiritual commitment.', 2021), 
('English Language', 'WAEC', 'The adjective "pragmatic" as used in the sentence "We need to be more pragmatic in the way we handle sensitive matters" means:', 'practical', 'realistic', 'logical', 'rational', NULL, 'A', 'The adjective "pragmatic" means practical, realistic, logical, rational and critical.', 2021), 
('English Language', 'WAEC', 'The verb "rebutted" in "The governor rebutted all the allegations against him" denotes:', 'refuted', 'disproved', 'denied', 'contradicted', NULL, 'A', 'The verb "rebutted" in the sentence denotes refuted, disproved, denied and contradicted. To rebut means to deny the truth of something, especially by presenting arguments that disprove it.', 2021), 
('English Language', 'WAEC', 'An injunction is a pronouncement, decree, judgment or order by a court of law to refrain someone or a group from doing a particular act.', 'A pronouncement', 'A decree', 'A judgment', 'An order', NULL, 'B', 'An injunction is a pronouncement, decree, judgment or order by a court of law to refrain someone or a group from doing a particular act.', 2021), 
('English Language', 'WAEC', 'Alleviation means the act of reducing, relieving or mitigating a challenge or anything unpleasant.', 'reducing', 'relieving', 'mitigating', 'eliminating', NULL, 'A', 'Alleviation means the act of reducing, relieving or mitigating a challenge or anything unpleasant, in the given case, poverty.', 2021), 
('English Language', 'WAEC', 'I won''t go to the cinema with you; I have _________ the movie.', 'seen', 'been seeing', 'have seen', 'had seen', NULL, 'A', 'The sentence should read "I won''t go to the cinema with you; I have seen the movie." The appropriate verb for the space provides is present perfect verb "have seen".', 2021), 
('English Language', 'WAEC', 'He provided a _________ report on the recently concluded meeting.', 'on', 'about', 'for', 'of', NULL, 'A', 'In the given sentence, the appropriate preposition to collocate with the noun "report" is "on", as in "He provided a detailed report on the recently concluded meeting."', 2021), 
('English Language', 'WAEC', 'The phrase "it''s" could be "it has" or "it is". What follows depends on the context with which it is used.', 'it has', 'it is', 'it was', 'it were', NULL, 'A', 'The phrase "it''s" could be "it has" or "it is". What follows depends on the context with which it is used. Since, the verb "been" follows "it''s", the answer is "has".', 2021), 
('English Language', 'WAEC', 'The sentence should read "If I had known, I would not have come."', 'would', 'could', 'should', 'might', NULL, 'A', 'The sentence should read "If I had known, I would not have come." It is a subjunctive statement used to express that it is a statement that did not happen in the past when it was expected or had the chance to.', 2021), 
('English Language', 'WAEC', 'Since the time of the day is not specified, neither "morning" nor "evening" should be preceded by article "the".', 'morning till evening', 'morning to evening', 'from morning till evening', 'from morning to evening', NULL, 'D', 'Since the time of the day is not specified, neither "morning" nor "evening" should be preceded by article "the". Note that a sentence like "I saw him in the morning" refers to a specific time of the morning, say 11am.', 2021), 
('English Language', 'WAEC', 'The sentence should read "He did it, but not quite the way I had expected".', 'quite', 'actually', 'exactly', 'so', NULL, 'A', 'The sentence should read "He did it, but not quite the way I had expected". The "quite" in the sentence means "relatively", "actually", "exactly". Note that "so" is not the right option because "the way" has been given in the sentence.', 2021), 
('English Language', 'WAEC', 'I have _________ the cinema with you.', 'been', 'seen', 'have seen', 'had seen', NULL, 'A', 'The sentence should read "I won''t go to the cinema with you; I have seen the movie." The appropriate verb for the space is present perfect "have seen".', 2021), 
('English Language', 'WAEC', 'The plural of "mother-in-law" is "mothers-in-law". Only mother takes the plural suffix "-s".', 'mother-in-laws', 'mothers-in-laws', 'mothers-in-law', 'mother-in-law', NULL, 'C', 'The plural of "mother-in-law" is "mothers-in-law". Only mother takes the plural suffix "-s".', 2021), 
('English Language', 'WAEC', 'The adjective "prone" always collocates with "to". "Be prone to something" means tending to suffer from an illness or show a particular negative characteristic.', 'to', 'for', 'of', 'with', NULL, 'A', 'The adjective "prone" always collocates with "to". "Be prone to something" means tending to suffer from an illness or show a particular negative characteristic.', 2021), 
('English Language', 'WAEC', 'Nigerian school teachers regularly meted out physical punishment to their pupils. The appropriate phrase is:', 'meted out', 'meted off', 'meted on', 'meted up', NULL, 'A', 'Met collocates with both the adverb "out" and the preposition "to" anything the phrasal verb is used.', 2021), 
('English Language', 'WAEC', 'The conjunction _________ means despite, in spite of or still.', 'yet', 'still', 'but', 'however', NULL, 'A', 'The conjunction "yet" means despite, in spite of or still. It is a contrastive conjunction appropriate for the sentence. Note that "still yet" is repetitive and so, incorrect.', 2021), 
('English Language', 'WAEC', 'The sentence should read "You cannot come between my sister and me."', 'me', 'I', 'myself', 'mine', NULL, 'A', 'The sentence should read "You cannot come between my sister and me". The space provided is an object space and it needs an object pronoun — me. The sentence can be rewritten as you cannot come between us (= my sister and me).', 2021);
